import itertools
from collections import defaultdict
from typing import Set, List, Optional, Iterable

import numpy as np
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.bundle_classifier import get_bundle_classifier_from_name
from geosat.psanp.abstractions.bundler import Bundle
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.tools.classification_code import SimpleClassificationCode

from psanp.classifiers.tensorflow.point_net_classifiers.data_normalization import (
    normalize_data,
    voxelize_cloud,
)
from psanp.classifiers.tensorflow.point_net_classifiers.load_graph import load_graph


class PointNetClassifier(Classifier):
    def __init__(self, stage_name: Optional[str] = None):
        super().__init__(stage_name)
        bundle: Bundle = get_bundle_classifier_from_name(self.stage_name)
        self._import_training_data(**bundle["database"])

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if not cloud:
            return (cloud,)
        codes_dict = {"codes": pipeline_metadata.classification_codes, "delimiter": "/"}
        classification_codes = SimpleClassificationCode.from_dict(codes_dict)
        self._cloud_classification(cloud, classification_codes)
        return (cloud,)

    def input_classes(self) -> Set[str]:
        return {self.input_class}

    def output_classes(self) -> Set[str]:
        return {self.output_class}

    @classmethod
    def options(cls) -> List[Option]:
        return []

    def _import_training_data(self, input_class, output_class, batch_size, vectors):
        self.input_class = input_class
        self.output_class = output_class
        self.batch_size = batch_size
        (
            self.sess,
            self.y_pred,
            self.point_cloud,
            self.label,
            self.is_training,
        ) = load_graph(vectors)

    def predict(self, data):
        feed_dict = {
            self.point_cloud: data,
            self.label: np.ones((self.batch_size, 512)),
            self.is_training: False,
        }
        pred_val = self.sess.run([self.y_pred], feed_dict=feed_dict)
        pred_val = pred_val[0]
        classification = np.argmax(pred_val, axis=2)
        probability = np.max(pred_val, axis=2)
        index_low_probalibity = probability < 0.8
        classification[index_low_probalibity] = 0
        return classification

    @staticmethod
    def _get_index_mapping(cloud, in_class_code):
        return np.where(cloud.classification == in_class_code)[0]

    def _cloud_classification(self, cloud, classification_codes):
        in_class_code = classification_codes[self.input_class]
        out_class_code = classification_codes[self.output_class]
        selected_indices = self._get_index_mapping(cloud, in_class_code)
        selected_cloud = cloud[selected_indices]
        voxel_point, reference_table = voxelize_cloud(
            selected_cloud, method=np.mean, class_whitelist=[in_class_code]
        )
        normalized_data_set, index_set = normalize_data(voxel_point)
        classified_voxel_index = []
        data_temps = []
        count = 0
        id_temps = []
        for id_data, normalized_data in enumerate(normalized_data_set):
            data_temps.append(normalized_data)
            id_temps.append(id_data)
            count += 1
            if count % self.batch_size == 0:
                data_temps = np.array(data_temps)
                classification = self.predict(data_temps)
                classification_flag = classification == 1
                for i in range(self.batch_size):
                    classified_voxel_index.append(
                        index_set[id_temps[i]][classification_flag[i]]
                    )
                data_temps = []
                id_temps = []
        if len(data_temps) > 0:
            for _ in range(self.batch_size - len(data_temps)):
                data_temps.append(data_temps[-1])
                id_temps.append(id_temps[-1])
            data_temps = np.array(data_temps)
            classification = self.predict(data_temps)
            classification_flag = classification == 1
            for i in range(self.batch_size):
                classified_voxel_index.append(
                    index_set[id_temps[i]][classification_flag[i]]
                )
        try:
            classified_voxel_index = np.concatenate(classified_voxel_index)
        except ValueError:
            classified_voxel_index = np.array([])
        classified_index = []
        for voxel_i in classified_voxel_index:
            classified_index.append(reference_table[voxel_i])
        try:
            classified_index = np.concatenate(classified_index)
            cloud.classification[selected_indices[classified_index]] = out_class_code
        except ValueError:
            pass


class PointNetRailClassifier(PointNetClassifier):
    @staticmethod
    def _get_high_points_index(cloud, resolution=0.2, min_h=0.05, max_h=0.4):
        x = cloud.coords[:, 0]
        y = cloud.coords[:, 1]
        z = cloud.coords[:, 2]
        pixel_x = (x - min(x) / resolution).astype(int)
        pixel_y = (y - min(y) / resolution).astype(int)
        pixel_coordinates = np.column_stack((pixel_x, pixel_y))
        map_pixel_point = defaultdict(list)
        indices = itertools.count()
        for point_index, pixel_index in zip(indices, pixel_coordinates):
            map_pixel_point[tuple(pixel_index)].append(point_index)
        valid_index = []
        for pixel_index, point_index in map_pixel_point.items():
            point_index = np.array(point_index)
            min_z = min(z[point_index])
            flag = (z[point_index] - min_z > min_h) * (z[point_index] - min_z < max_h)
            valid_index.append(point_index[flag])
        try:
            return np.concatenate(valid_index)
        except ValueError:
            return []

    @classmethod
    def _get_index_mapping(cls, cloud, in_class_code):
        ground_index = np.where(cloud.classification == in_class_code)[0]
        cloud_ground = cloud[ground_index]
        high_point_index = cls._get_high_points_index(cloud_ground)
        return ground_index[high_point_index]
